Method.Source:
[Form]
public class DBMSQLText extends FormRun
{

    Object callerFormRun;
    DBMSQLHandle statementHandle;
    DBMSQLHandle planHandle;
    DBMSQLQueryStoreQueryTextId querytextId;
    DBMSQLQueryStorePlanId queryPlanId;
    boolean isPlanCacheBased;
}

public void init()
{
    if (element.args().caller()
        && element.args().caller() is FormRun)
    {
        FormRun callerForm = element.args().caller() as FormRun;
        if (formHasMethod(callerForm, identifierStr(getSQLHandle))
            && formHasMethod(callerForm, identifierStr(getPlanHandle)))
        {
            callerFormRun = callerForm;
            isPlanCacheBased = true;
        }
        else  if (formHasMethod(callerForm, identifierStr(getQueryTextId))
        && formHasMethod(callerForm, identifierStr(getQueryPlanId)))
        {
            callerFormRun = callerForm;
            isPlanCacheBased = false;
        }
        else
        {
            throw error(Error::wrongUseOfFunction(funcName()));
        }
    }
    super();
    str SQLWarning =  "@DBMonitor:SQLTextWarning";
    str SQLTextSample;
    if (isPlanCacheBased)
    {
        statementHandle = callerFormRun.getSQLHandle();
        planHandle = callerFormRun.getPlanHandle();
        SQLTextSample = DBMSQLUtils::getSqlTextSample(statementHandle, planHandle);
    }
    else
    {
        querytextId = callerFormRun.getQueryTextId();
        queryPlanId = callerFormRun.getQueryPlanId();
        SQLTextSample = DBMSQLUtils::getSqlTextSampleQueryStore(querytextId, queryPlanId);
    }
    SQLText.text(SQLWarning+'\n'+SQLTextSample);
}
